# ─── Cost Analysis Extension ─────────────────────────────────────────────────

from strawberry.extensions import SchemaExtension
from strawberry.types import Info
from graphql import (
    DocumentNode,
    FieldNode,
    FragmentSpreadNode,
    InlineFragmentNode,
    OperationDefinitionNode,
)


MAX_QUERY_COST = 500


def _calculate_field_cost(
    node,
    fragments: dict,
    depth: int = 0,
) -> int:
    """
    Calculate cost of a selection set.
    Each scalar field = 1, each object/list field = 2 + children cost.
    Multiplied by depth factor to penalize deeply nested queries.
    """
    cost = 0
    selections = getattr(node, "selection_set", None)
    if selections is None:
        return 1  # leaf / scalar

    for sel in selections.selections:
        if isinstance(sel, FieldNode):
            child_selections = sel.selection_set
            if child_selections is None:
                cost += 1
            else:
                # List/object fields cost more
                cost += 2 + _calculate_field_cost(sel, fragments, depth + 1)
        elif isinstance(sel, InlineFragmentNode):
            cost += _calculate_field_cost(sel, fragments, depth)
        elif isinstance(sel, FragmentSpreadNode):
            frag = fragments.get(sel.name.value)
            if frag:
                cost += _calculate_field_cost(frag, fragments, depth)

    return cost


class CostAnalysisExtension(SchemaExtension):
    """
    Reject queries whose estimated cost exceeds MAX_QUERY_COST.
    This prevents resource-exhaustion attacks where a client requests
    extremely wide or deeply nested data.
    """

    def on_operation(self):
        execution_context = self.execution_context
        document: DocumentNode = execution_context.graphql_document
        if document is None:
            yield
            return

        fragments = {
            defn.name.value: defn
            for defn in document.definitions
            if hasattr(defn, "name") and defn.name and not isinstance(defn, OperationDefinitionNode)
        }

        total_cost = 0
        for defn in document.definitions:
            if isinstance(defn, OperationDefinitionNode):
                total_cost += _calculate_field_cost(defn, fragments)

        if total_cost > MAX_QUERY_COST:
            raise Exception(
                f"Query cost {total_cost} exceeds maximum allowed cost {MAX_QUERY_COST}. "
                f"Please reduce the number of fields or nesting depth."
            )

        yield


# ─── Rate Limiting Extension ─────────────────────────────────────────────────

import time
from collections import defaultdict

# Simple in-memory token-bucket rate limiter
_rate_limit_buckets: dict[str, list] = defaultdict(list)
RATE_LIMIT_WINDOW = 60  # seconds
RATE_LIMIT_MAX_REQUESTS = 100  # max requests per window per client


class RateLimitExtension(SchemaExtension):
    """
    Simple per-client rate limiting based on IP or a fixed key.
    """

    def on_operation(self):
        request = self.execution_context.context.get("request") if isinstance(self.execution_context.context, dict) else getattr(self.execution_context.context, "request", None)

        client_id = "anonymous"
        if request is not None:
            client_host = getattr(request.client, "host", None) if hasattr(request, "client") and request.client else None
            if client_host:
                client_id = client_host

        now = time.time()
        bucket = _rate_limit_buckets[client_id]
        # Prune old entries
        _rate_limit_buckets[client_id] = [t for t in bucket if now - t < RATE_LIMIT_WINDOW]
        bucket = _rate_limit_buckets[client_id]

        if len(bucket) >= RATE_LIMIT_MAX_REQUESTS:
            raise Exception(
                f"Rate limit exceeded. Maximum {RATE_LIMIT_MAX_REQUESTS} requests "
                f"per {RATE_LIMIT_WINDOW} seconds."
            )

        bucket.append(now)
        yield


