@strawberry.type
class Category:
    id: int
    name: str
    description: Optional[str]

    @strawberry.field
    def parent(self, info: strawberry.types.Info) -> Optional["Category"]:
        session: Session = info.context["session"]
        cat = session.query(CategoryModel).get(self.id)
        if cat and cat.parent:
            return Category(
                id=cat.parent.id,
                name=cat.parent.name,
                description=cat.parent.description,
            )
        return None

    @strawberry.field
    def children(self, info: strawberry.types.Info) -> List["Category"]:
        session: Session = info.context["session"]
        cat = session.query(CategoryModel).options(joinedload(CategoryModel.children)).get(self.id)
        if cat is None:
            return []
        return [
            Category(id=c.id, name=c.name, description=c.description)
            for c in cat.children
        ]

    @strawberry.field
    def products(self, info: strawberry.types.Info, limit: int = 20, offset: int = 0) -> List["Product"]:
        session: Session = info.context["session"]
        cat = session.query(CategoryModel).get(self.id)
        if cat is None:
            return []
        products = cat.products[offset: offset + limit]
        return [_product_from_model(p) for p in products]


