@strawberry.type
class Product:
    id: int
    name: str
    description: Optional[str]
    price: float
    created_at: Optional[str]

    @strawberry.field
    def seller(self, info: strawberry.types.Info) -> Optional[Seller]:
        session: Session = info.context["session"]
        product = session.query(ProductModel).options(joinedload(ProductModel.seller)).get(self.id)
        if product and product.seller:
            s = product.seller
            return Seller(id=s.id, name=s.name, email=s.email, rating=s.rating)
        return None

    @strawberry.field
    def reviews(self, info: strawberry.types.Info, limit: int = 50, offset: int = 0) -> List[Review]:
        session: Session = info.context["session"]
        reviews = (
            session.query(ReviewModel)
            .filter(ReviewModel.product_id == self.id)
            .offset(offset)
            .limit(limit)
            .all()
        )
        return [
            Review(
                id=r.id,
                author=r.author,
                content=r.content,
                rating=r.rating,
                created_at=r.created_at.isoformat() if r.created_at else None,
            )
            for r in reviews
        ]

    @strawberry.field
    def categories(self, info: strawberry.types.Info) -> List[Category]:
        session: Session = info.context["session"]
        product = session.query(ProductModel).options(joinedload(ProductModel.categories)).get(self.id)
        if product is None:
            return []
        return [
            Category(id=c.id, name=c.name, description=c.description)
            for c in product.categories
        ]

    @strawberry.field
    def images(self, info: strawberry.types.Info) -> List[Image]:
        session: Session = info.context["session"]
        imgs = session.query(ImageModel).filter(ImageModel.product_id == self.id).all()
        return [
            Image(id=i.id, url=i.url, alt_text=i.alt_text, is_primary=bool(i.is_primary))
            for i in imgs
        ]

    @strawberry.field
    def average_rating(self, info: strawberry.types.Info) -> Optional[float]:
        session: Session = info.context["session"]
        from sqlalchemy import func
        result = session.query(func.avg(ReviewModel.rating)).filter(
            ReviewModel.product_id == self.id
        ).scalar()
        return round(float(result), 2) if result else None

    @strawberry.field
    def review_count(self, info: strawberry.types.Info) -> int:
        session: Session = info.context["session"]
        from sqlalchemy import func
        result = session.query(func.count(ReviewModel.id)).filter(
            ReviewModel.product_id == self.id
        ).scalar()
        return result or 0


def _product_from_model(p: ProductModel) -> Product:
    return Product(
        id=p.id,
        name=p.name,
        description=p.description,
        price=p.price,
        created_at=p.created_at.isoformat() if p.created_at else None,
    )


# ─── Query ───────────────────────────────────────────────────────────────────

@strawberry.type
class Query:
    @strawberry.field
    def products(
        self,
        info: strawberry.types.Info,
        limit: int = 20,
        offset: int = 0,
        search: Optional[str] = None,
        min_price: Optional[float] = None,
        max_price: Optional[float] = None,
        category_id: Optional[int] = None,
        seller_id: Optional[int] = None,
    ) -> List[Product]:
        session: Session = info.context["session"]
        query = session.query(ProductModel)

        if search:
            query = query.filter(
                ProductModel.name.ilike(f"%{search}%")
                | ProductModel.description.ilike(f"%{search}%")
            )
        if min_price is not None:
            query = query.filter(ProductModel.price >= min_price)
        if max_price is not None:
            query = query.filter(ProductModel.price <= max_price)
        if seller_id is not None:
            query = query.filter(ProductModel.seller_id == seller_id)
        if category_id is not None:
            query = query.join(ProductModel.categories).filter(CategoryModel.id == category_id)

        products = query.offset(offset).limit(limit).all()
        return [_product_from_model(p) for p in products]

    @strawberry.field
    def product(self, info: strawberry.types.Info, id: int) -> Optional[Product]:
        session: Session = info.context["session"]
        p = session.query(ProductModel).get(id)
        if p is None:
            return None
        return _product_from_model(p)

    @strawberry.field
    def categories(self, info: strawberry.types.Info, top_level_only: bool = False) -> List[Category]:
        session: Session = info.context["session"]
        query = session.query(CategoryModel)
        if top_level_only:
            query = query.filter(CategoryModel.parent_id.is_(None))
        cats = query.all()
        return [
            Category(id=c.id, name=c.name, description=c.description)
            for c in cats
        ]

    @strawberry.field
    def category(self, info: strawberry.types.Info, id: int) -> Optional[Category]:
        session: Session = info.context["session"]
        c = session.query(CategoryModel).get(id)
        if c is None:
            return None
        return Category(id=c.id, name=c.name, description=c.description)

    @strawberry.field
    def sellers(self, info: strawberry.types.Info, limit: int = 20, offset: int = 0) -> List[Seller]:
        session: Session = info.context["session"]
        sellers = session.query(SellerModel).offset(offset).limit(limit).all()
        return [
            Seller(id=s.id, name=s.name, email=s.email, rating=s.rating)
            for s in sellers
        ]

    @strawberry.field
    def seller(self, info: strawberry.types.Info, id: int) -> Optional[Seller]:
        session: Session = info.context["session"]
        s = session.query(SellerModel).get(id)
        if s is None:
            return None
        return Seller(id=s.id, name=s.name, email=s.email, rating=s.rating)


# ─── Mutations ───────────────────────────────────────────────────────────────

@strawberry.input
class CreateReviewInput:
    product_id: int
    author: str
    content: Optional[str] = None
    rating: int


@strawberry.input
class CreateProductInput:
    name: str
    description: Optional[str] = None
    price: float
    seller_id: Optional[int] = None
    category_ids: Optional[List[int]] = None


@strawberry.type
class Mutation:
    @strawberry.mutation
    def create_product(self, info: strawberry.types.Info, input: CreateProductInput) -> Product:
        session: Session = info.context["session"]
        product = ProductModel(
            name=input.name,
            description=input.description,
            price=input.price,
            seller_id=input.seller_id,
        )
        if input.category_ids:
            categories = session.query(CategoryModel).filter(
                CategoryModel.id.in_(input.category_ids)
            ).all()
            product.categories = categories

        session.add(product)
        session.commit()
        session.refresh(product)
        return _product_from_model(product)

    @strawberry.mutation
    def add_review(self, info: strawberry.types.Info, input: CreateReviewInput) -> Review:
        session: Session = info.context["session"]

        # Validate rating
        if input.rating < 1 or input.rating > 5:
            raise ValueError("Rating must be between 1 and 5")

        product = session.query(ProductModel).get(input.product_id)
        if product is None:
            raise ValueError(f"Product with id {input.product_id} not found")

        review = ReviewModel(
            product_id=input.product_id,
            author=input.author,
            content=input.content,
            rating=input.rating,
        )
        session.add(review)
        session.commit()
        session.refresh(review)

        return Review(
            id=review.id,
            author=review.author,
            content=review.content,
            rating=review.rating,
            created_at=review.created_at.isoformat() if review.created_at else None,
        )

    @strawberry.mutation
    def delete_product(self, info: strawberry.types.Info, id: int) -> bool:
        session: Session = info.context["session"]
        product = session.query(ProductModel).get(id)
        if product is None:
            return False
        session.delete(product)
        session.commit()
        return True


# ─── Schema ──────────────────────────────────────────────────────────────────

schema = strawberry.Schema(
    query=Query,
    mutation=Mutation,
    extensions=[
        QueryDepthLimiter(max_depth=10),
        CostAnalysisExtension,
        RateLimitExtension,
    ],
)


# ─── ASGI App ────────────────────────────────────────────────────────────────

from strawberry.asgi import GraphQL as StarletteGraphQL
from starlette.requests import Request
from starlette.responses import Response
from starlette.websockets import WebSocket


class GraphQLApp(StarletteGraphQL):
    async def get_context(self, request: Request | WebSocket, response: Optional[Response] = None):
        session = SessionLocal()
        return {
            "session": session,
            "request": request,
            "response": response,
        }


app = GraphQLApp(schema)


# ─── Main ────────────────────────────────────────────────────────────────────

if __name__ == "__main__":
    import uvicorn

    init_db()
    seed_db()

    print("Starting GraphQL API server at http://localhost:8000/graphql")
    print()
    print("Security measures enabled:")
    print(f"  - Query depth limit: 10 levels")
    print(f"  - Query cost analysis: max cost {MAX_QUERY_COST}")
    print(f"  - Rate limiting: {RATE_LIMIT_MAX_REQUESTS} requests per {RATE_LIMIT_WINDOW}s")
    print()

    uvicorn.run(app, host="0.0.0.0", port=8000)